TEXT={"firstName":"FirstName","lastName":"LastName","email":"Email","phone":"Phone","jobTitle":"JobTitle","companyName":"CompanyName","source":"Source","status":"Status","rating":"Rating","ownerUserId":"OwnerUserId","city":"City","country":"Country","notes":"Notes","nextFollowUpAt":"NextFollowUpAt"}
