    skip=iv(data.get("skip")) if data.get("skip") not in (None,"") else "0"
    sort=data.get("sort") or "CreatedAt"
    if sort not in ("CreatedAt","UpdatedAt","Value","LastName","StageId","NextFollowUpAt","LastContactedAt"):
        sort="CreatedAt"
    direction="ASC" if str(data.get("dir") or "desc").lower()=="asc" else "DESC"
