import json
raw = """${body}"""
try:
    events = json.loads(raw) if raw and raw.strip() else []
except Exception:
    events = []
if isinstance(events, dict):
    events = [events]
if not isinstance(events, list):
    events = []
def s(v):
    if v is None or v=="": return "NULL"
    return "'"+str(v).replace("'","''")+"'"
stmts = []
for e in events:
    if not isinstance(e, dict): continue
    ev = e.get("event") or ""
    email = e.get("email") or ""
    sgid = str(e.get("sg_message_id") or "").split(".")[0]
    url = e.get("url") or ""
    stmts.append("INSERT INTO email_events (ProviderMessageId, EventType, Email, Url, Payload) VALUES ("+s(sgid)+", "+s(ev)+", "+s(email)+", "+s(url)+", "+s(json.dumps(e))+");")
    if ev == "open":
        stmts.append("UPDATE emails SET Status='opened', OpenedAt=CURRENT_TIMESTAMP WHERE ProviderMessageId = "+s(sgid)+" AND OpenedAt IS NULL;")
    elif ev in ("bounce","dropped","spamreport"):
